// ============================================================
// PublicationWorker — Préparer l'appel au PublicationAgent
// ============================================================
// Format attendu par PublicationAgent :
//   { job_id, correlation_id, action: 'PUBLISH_CONTENT' }
// ============================================================

const input = $input.first().json.body || $input.first().json;

return [{
  json: {
    tenant_id: input.tenant_id || 1,
    job_id: input.job_id,
    correlation_id: input.correlation_id || '',
    action: 'PUBLISH_CONTENT',
    channel_name: input.channel_name || '',
    _queue_name: input.queue_name || '',
    _queue_tenant_id: input.tenant_id,
    _queue_attempt: input.attempt || 1,
  }
}];

// ============================================================
// Analyser résultat du PublicationAgent
// ============================================================
// Résultats possibles :
//   PUBLISHED → succès ✅
//   FAILED_CREDENTIALS → erreur définitive (pas de retry)
//   FAILED_PRE_PUBLICATION → erreur définitive
//   FAILED_PUBLICATION → erreur potentiellement transient (retry)
//   PUBLICATION_DEFERRED → replanifié (pas de retry immédiat)
// ============================================================

const result = $input.first().json;
const prep = $('Préparer appel Publication').first().json;
const p = result.payload || result;

const resultStatus = p.result_status || p.status || 'UNKNOWN';
const jobId = p.job_id || prep.job_id;
const correlation_id = result.correlation_id || prep.correlation_id;

// Erreurs définitives (ne pas retry)
const permanentErrors = [
  'FAILED_CREDENTIALS',
  'FAILED_PRE_PUBLICATION',
  'PUBLICATION_DEFERRED',
];

const isSuccess = resultStatus === 'PUBLISHED';
const isPermanent = permanentErrors.includes(resultStatus);

if (isSuccess) {
  return [{
    json: {
      worker: 'PublicationWorker',
      status: 'completed',
      job_id: jobId,
      correlation_id,
      result_status: resultStatus,
      platform_post_id: p.platform_post_id || null,
      channel_name: prep.channel_name,
      timestamp: new Date().toISOString(),
    }
  }];
}

if (isPermanent) {
  // Répondre OK pour que BullMQ ne retente pas
  return [{
    json: {
      worker: 'PublicationWorker',
      status: 'completed_with_error',
      job_id: jobId,
      correlation_id,
      result_status: resultStatus,
      error_code: p.error_code || resultStatus,
      permanent_failure: true,
      channel_name: prep.channel_name,
      timestamp: new Date().toISOString(),
    }
  }];
}

// Erreur transient (FAILED_PUBLICATION) → throw pour retry BullMQ
throw new Error(`Publication failed (transient): ${resultStatus} — ${p.error_message || 'Unknown error'}`);
